"""Juicy manual translations 201-300."""

T = {
201: {"nativeDefinition": "To schedule something tentatively.", "japaneseMeaning": "（予定を）仮押さえする", "etymology": "pencil in（鉛筆で書く）が仮の予定を表す。", "examples": {"B": "ごめん、土曜のランチ仮押さえしてくれたのに、来週にずらせる？", "C": "まだ行けるかわからないけど、とりあえず仮押さえしていい？スケジュールが確定したら連絡する。", "D": "意図的に予約する。"}},
202: {"nativeDefinition": "To continue through difficulties despite obstacles.", "japaneseMeaning": "（困難を）乗り越える、押し通す", "etymology": "push through（押し抜ける）が障害を乗り越えることを表す。", "examples": {"B": "今つらい時期だけど、あと数週間押し通せば良くなる。", "C": "明確な目標があると、障害を乗り越えて前に進める。", "D": "何かを通過して進む。"}},
203: {"nativeDefinition": "To make oneself visible or available, especially socially.", "japaneseMeaning": "（自分を）さらけ出す、積極的に出る", "etymology": "put oneself out there（外に出す）が積極的に行動することを表す。", "examples": {"B": "自分をさらけ出すのを恐れないで。拒絶を恐れて生きてたら、チャンスを逃し続ける。", "C": "人当たりのいい人になりたいなら、コンフォートゾーンから出て積極的に行動しないと。", "D": "もっと社交的になる。"}},
204: {"nativeDefinition": "Within reasonable limits; not excessively.", "japaneseMeaning": "適度に、ほどほどに", "etymology": "in moderation（節度を持って）が過度でないことを表す。", "examples": {"B": "適度にやる分には備蓄しても問題ないけど、これはトイレットペーパーが多すぎ。城を建ててるみたい。", "C": "Netflixの一気見はやめないと。いつも時間を見失う。何事もほどほどに。", "D": "合理的な範囲内で。"}},
205: {"nativeDefinition": "To have plenty of time available.", "japaneseMeaning": "時間はいくらでもある", "etymology": "all the time in the world（世界中の時間）が時間に余裕があることを表す。", "examples": {"B": "人は時間はいくらでもあると思いがちだけど、人生はとても短い。", "C": "夏休みだから時間はいくらでもあるけど、何すればいいかわからない。", "D": "たくさんの時間がある。"}},
206: {"nativeDefinition": "Finally and completely, for the last time.", "japaneseMeaning": "今こそ完全に、最後に", "etymology": "once and for all（一度で永遠に）が完全に終わらせることを表す。", "examples": {"B": "Facebookを完全にやめた。ベビーブーマーが若者に説教するのにうんざりしてた。", "C": "これで最後に決めよう。ビートルズとブラック・アイド・ピース、どっちが史上最高のバンド？", "D": "完全にそして最終的に。"}},
207: {"nativeDefinition": "To get into a vehicle; to join someone.", "japaneseMeaning": "（車に）乗る、一緒に行く", "etymology": "hop on（飛び乗る）が気軽に乗ることを表す。", "examples": {"B": "30分後にどこか行かなきゃいけないけど、途中で降ろしてあげられるよ。", "C": "今モールに向かってる。一緒に行く？", "D": "乗る。"}},
208: {"nativeDefinition": "To remain in someone's memory or affect them long-term.", "japaneseMeaning": "（人に）ずっと残る、心に残る", "etymology": "stay with（一緒にいる）が記憶や影響に残ることを表す。", "examples": {"B": "子どもの頃の経験は大人になってもずっと残るから、親は子どもに言うことに気をつけるべき。", "C": "カエルを食べてる写真が本当に気持ち悪かった。一生忘れられない。", "D": "誰かの記憶に残る。"}},
209: {"nativeDefinition": "To use the last remaining good options because better ones are gone.", "japaneseMeaning": "（選択肢が）底をつく、使い果たす", "etymology": "scrape the bottom of the barrel（樽の底をこする）が最後の手段に迫ることを表す。", "examples": {"B": "待って、1年前に似たような番組なかった？アイデアの底をつかしてる。", "C": "また有名人を候補にするなんて信じられない。本当に選択肢の底をつかしてる。", "D": "良い選択肢がなくなる。"}},
210: {"nativeDefinition": "To begin a conversation or relationship.", "japaneseMeaning": "（会話・関係を）始める", "etymology": "strike up（打ち始める）が会話や関係の開始を表す。", "examples": {"B": "彼女と会話を始めたいんだけど、緊張しすぎて。", "C": "兄とはすぐにいい関係を築けた。みんなが変人だと思ってるのに。僕も変なのかな？", "D": "適切に始める。"}},
211: {"nativeDefinition": "No longer available as an option.", "japaneseMeaning": "（選択肢が）なくなった、もう無理", "etymology": "off the table（テーブルの外）が交渉の選択肢から外れることを表す。", "examples": {"B": "ごめん、オファーはもうなくなった。時間がない。", "C": "今はキャリアに集中したいから、結婚は今のところ選択肢にない。", "D": "選択肢ではない。"}},
212: {"nativeDefinition": "To research or study something by reading.", "japaneseMeaning": "（〜について）調べる、読んで学ぶ", "etymology": "read up on（読んで調べる）が文献で学ぶことを表す。", "examples": {"B": "ロシア史を教えたことないけど、数日調べれば大丈夫だと思う。", "C": "来週面接する会社について調べてる。", "D": "何かを調査する。"}},
213: {"nativeDefinition": "A list of things one wants to do before dying.", "japaneseMeaning": "バケットリスト、死ぬ前にやりたいこと", "etymology": "bucket（バケツ）＋list（リスト）が「死ぬ前にやることリスト」の俗語。", "examples": {"B": "ビヨンセのコンサートに行くのがバケットリストのトップ。チケットは本当に取りにくいから、実現するかはわからない。", "C": "現時点でバケットリストでまだチェックしてないのは宇宙旅行だけ。", "D": "人生で達成したいことのリスト。"}},
214: {"nativeDefinition": "To trick or deceive someone, often into giving money.", "japaneseMeaning": "（人を）だます、騙す", "etymology": "con（詐欺）が人を騙すことを表す。", "examples": {"B": "全財産をスイス銀行に移すよう騙されて、お金が消えた。どれだけバカなの？", "C": "この男が人から金を騙し取ったって聞いた。証拠はないけど、噂が多い。噂には理由があるよね。", "D": "だまして何かをさせる。"}},
215: {"nativeDefinition": "To think very highly of someone.", "japaneseMeaning": "（人を）とても高く評価する", "etymology": "think the world of（世界ほど思う）が最高の評価を表す。", "examples": {"B": "ジョンは親友だから、彼のことをとても高く評価してる。", "C": "お父さんはあなたのことをとても高く評価してる。豚が飛ぶときに言ったのは本心じゃないよ。", "D": "誰かを高く評価する。"}},
216: {"nativeDefinition": "The most talented and intelligent people in a field.", "japaneseMeaning": "エリート、優秀な人材", "etymology": "best and brightest（最良で最も聡明）が一流の人材を表す。", "examples": {"B": "今夜シリコンバレーのエリートと夕食する。緊張する。", "C": "うちの会社はハードルが高く、エリートだけを雇う。", "D": "とても賢く知的な人々。"}},
217: {"nativeDefinition": "The newest and best version of something.", "japaneseMeaning": "最新かつ最高の", "etymology": "latest（最新）and greatest（最高）が最新モデルを表す。", "examples": {"B": "最新の情報はウェブサイトをチェックして。", "C": "新しいiPhoneが出るたびに最新モデルを買う意味ある？そんなに違わないよ。", "D": "最新で最高の。"}},
218: {"nativeDefinition": "Occasionally; in various places or times.", "japaneseMeaning": "たまにここそこ、所々", "etymology": "here and there（あちこち）が散発的にを表す。", "examples": {"B": "休暇中でもたまに運動するようにしてる。でもあまり気が乗らない。", "C": "モデルは副業で、たまにここそこお金になるけど、ずっとできることじゃない。", "D": "時折。"}},
219: {"nativeDefinition": "Having learned a skill without formal education.", "japaneseMeaning": "独学の、自学自習の", "etymology": "self（自分）＋taught（教えた）が独学を表す。", "examples": {"B": "本当に独学のピアニストはほとんどいない。", "C": "独学のアプリ開発者だけど、特別なことじゃない。無料のオンラインコースでたくさん学べる。", "D": "正式な教育なしに熟練した。"}},
220: {"nativeDefinition": "To express one's opinion openly.", "japaneseMeaning": "意見を述べる、自分の考えを言う", "etymology": "voice one's opinion（意見に声を与える）が公に意見を言うことを表す。", "examples": {"B": "人が意見を述べるのは反対しないけど、もっと聞いてほしい。", "C": "SNSで意見を言うのは控えてる。バカなこと言って自分の首を絞めたくないから。", "D": "自分の立場を表明する。"}},
221: {"nativeDefinition": "To resume; to improve or increase.", "japaneseMeaning": "（再開する）、（上向く・増える）", "etymology": "pick up（拾い上げる）が再開や改善を表す。", "examples": {"B": "もう行くね。来週また再開するから、今のうちに休む。じゃあね。", "C": "なぜかわからないけど、ここ数ヶ月で業績が本当に上向いた。", "D": "増加または改善する。"}},
222: {"nativeDefinition": "An additional professional opinion.", "japaneseMeaning": "セカンドオピニオン、第二の意見", "etymology": "second opinion（第二の意見）が別の専門家の見解を表す。", "examples": {"B": "オレンジはビタミンCが豊富で肌にいいと思うけど、セカンドオピニオンをもらってもいいよ。", "C": "アメリカ人はsurelyを絶対言わないって同意しない。聞いたことある。セカンドオピニオンが必要だ。", "D": "他の誰かからのアドバイス。"}},
223: {"nativeDefinition": "To gradually become quieter or less intense.", "japaneseMeaning": "（騒ぎが）静まる、収まる", "etymology": "die down（静かに死ぬ）が勢いが衰えることを表す。", "examples": {"B": "ツイートの通知がやっと静まった。数日で1万いいね超えたなんて信じられない。", "C": "先週オープンしてからこのレストランは大盛況。あの行列見て。落ち着くまで待とう。", "D": "静かになる。"}},
224: {"nativeDefinition": "To become upset or angry, often over something minor.", "japaneseMeaning": "キレる、ムキになる", "etymology": "triggered（引き金が引かれた）が過剰反応するスラング。", "examples": {"B": "陰で悪口言われてるって聞いてすごくムキになった。今回は見逃すけど。", "C": "ジェームズが体重をからかったとき、彼女はかなりムキになってた。卑怯な攻撃だったから仕方ない。", "D": "動揺する。"}},
225: {"nativeDefinition": "To behave very well and politely.", "japaneseMeaning": "良い子にする、行儀よくする", "etymology": "on one's best behavior（最高の行動で）が最善の振る舞いを表す。", "examples": {"B": "なんでいつも良い子にするよう言わなきゃいけないの？高級レストランで大声出しちゃダメなのはわかってるでしょ。", "C": "ランチ中、子どもたちは良い子にしてた。", "D": "とてもよく振る舞う。"}},
226: {"nativeDefinition": "To be familiar with the usual procedure.", "japaneseMeaning": "やり方はわかってる、お決まりでしょ", "etymology": "know the drill（手順を知る）が慣れた流れを表す。", "examples": {"B": "さあ子どもたち、寝る時間よ。お決まりでしょ。ベッドを整えて、スマホ消して、電気消して。", "C": "ほら、もうお決まりでしょ。食事中は肘をテーブルにつけない。", "D": "何をすべきかよく知っている。"}},
227: {"nativeDefinition": "To take care of something for someone.", "japaneseMeaning": "（〜は）任せて、カバーする", "etymology": "have got covered（カバーしてある）が対応済みを表す。", "examples": {"B": "ねえパパ、母の日は心配しないで。任せて。", "C": "昨日のウェビナー見逃した？カバーしてるよ。YouTubeで今見れる。", "D": "何かの面倒を見る。"}},
228: {"nativeDefinition": "Looking back a few years ago.", "japaneseMeaning": "数年前に遡ると", "etymology": "go back a few years（数年戻る）が過去を振り返る表現。", "examples": {"B": "数年前に遡ると、日本に来たばかりの頃は簡単なフレーズしか知らなかった。長い道のりを歩んできた。", "C": "数年前に遡ると、ほとんどの人はSiriが何かすら知らなかった。バーチャルアシスタントはずいぶん進化した。", "D": "数年前に呼ばれる。"}},
229: {"nativeDefinition": "Someone who hides nothing; completely transparent.", "japaneseMeaning": "オープンブック、何でもわかる人", "etymology": "open book（開いた本）が読みやすく秘密がないことを表す。", "examples": {"B": "僕は完全にオープンブック。顔を見れば何考えてるかわかる。", "C": "インスタに何でも投稿するから、僕の人生はオープンブックだ。", "D": "秘密のない人や物。"}},
230: {"nativeDefinition": "What's going on with someone or something?", "japaneseMeaning": "どうしたの、何のこと？", "etymology": "what's with（〜はどうした）が状況への疑問を表す。", "examples": {"B": "そのヒゲは何？大人っぽく見せようとしてるの？", "C": "ねえ、ベンは今日どうしたの？いつも陽気なのに、今日は曇り。", "D": "何かに何が起きている？"}},
231: {"nativeDefinition": "Unreliable; inconsistent.", "japaneseMeaning": "フレーク（約束を守らない）、不安定な", "etymology": "flaky（剥がれやすい）が約束を守らない人を表すスラング。", "examples": {"B": "インターネットがすごく不安定。ずっとラグい。", "C": "言った時間に来ない。本当にフレークだ。", "D": "不安定または信頼できない。"}},
232: {"nativeDefinition": "To provide a valuable lesson through experience, often negative.", "japaneseMeaning": "（人に）教訓を与える", "etymology": "teach a lesson（教訓を教える）が経験から学ばせることを表す。", "examples": {"B": "蚊に刺された。キャンプに行くときはいつも虫除け持ってるのに、昨日は忘れた。いい教訓になった。", "C": "すべての失敗が貴重な教訓を教えてくれる。", "D": "学ぶ機会を与える懲罰。"}},
233: {"nativeDefinition": "A particular field or area of activity.", "japaneseMeaning": "分野、領域", "etymology": "arena（競技場）が比喩的に活動分野を表す。", "examples": {"B": "アダムと僕は同じ会社だけど、別の分野で働いてるからあまり話さない。", "C": "数学の理解は多くの分野で役立つ。", "D": "分野。"}},
234: {"nativeDefinition": "To be told something frequently.", "japaneseMeaning": "よく言われる", "etymology": "get that a lot（それをよく聞く）が頻繁に言われることを表す。", "examples": {"B": "かっこいいって思う？よく言われるよ。", "C": "目の色がきれい。ごめん、よく言われる？", "D": "よくそう言われる。"}},
235: {"nativeDefinition": "In small amounts; tolerable only in limited doses.", "japaneseMeaning": "少量なら、少しずつなら", "etymology": "in small doses（小さな量で）が少量なら耐えられることを表す。", "examples": {"B": "新しい仕事への露出は少量ならいいけど、頻繁だとストレス溜まる。", "C": "毎日ドヤ顔の自撮りをインスタに投稿して褒め言葉を釣る。少量なら我慢できるけど、これは多すぎ。", "D": "少量で。"}},
236: {"nativeDefinition": "To be in a good situation or relationship.", "japaneseMeaning": "うまくいってる、いい関係を築いている", "etymology": "have a good thing going（いいことが進行中）が順調な状況を表す。", "examples": {"B": "本当に別れるの？いい関係築いてるのに。バカな喧嘩で台無しにするのはもったいない。", "C": "この会社ではうまくいってるから、しばらく居続けようと思う。", "D": "物事がうまくいっている状況にある。"}},
237: {"nativeDefinition": "That would change the situation or opinion.", "japaneseMeaning": "それは話が違う、別の話", "etymology": "that's a different story（それは別の話）が状況が変わることを表す。", "examples": {"B": "普通は違法なことにお金を払うのは正しくない。でも命を救うためなら、それは別の話。", "C": "犬は大好きだけど、チキンナゲットを食べられたら、それは別の話。", "D": "それは意見を変えるだろう。"}},
238: {"nativeDefinition": "To occur to someone as a thought.", "japaneseMeaning": "（考えが）よぎる、思いつく", "etymology": "cross one's mind（心を横切る）がふと思い浮かぶことを表す。", "examples": {"B": "数年前まで、この単語リストを本にするなんて思いもしなかった。", "C": "スペイン語を学ぼうかと思ったけど、今はイタリア語に集中した方がいい。まだ学ぶことがたくさんある。", "D": "誰かに思い浮かぶ。"}},
239: {"nativeDefinition": "To require some improvement.", "japaneseMeaning": "（もう少し）改善が必要", "etymology": "need a bit of work（少しの仕事が必要）が改善の余地があることを表す。", "examples": {"B": "新居の庭はまだ改善が必要。12月前に終わらせようとしてる。ここでクリスマスパーティーする予定だから。", "C": "ウェブデザインのスキルはもう少し改善が必要。後でケイトに相談する。プロだから。", "D": "いくらかの改善が必要。"}},
240: {"nativeDefinition": "To lose energy or motivation.", "japaneseMeaning": "（勢いが）なくなる、疲れてくる", "etymology": "run out of steam（蒸気が尽きる）が力が衰えることを表す。", "examples": {"B": "この経済学者は中国経済がすぐ勢いを失うかもしれないと言ってるけど、わからない。", "C": "本の大部分は書き終えたけど、だんだん疲れてきた。表紙デザインはクリスマス後に回す。", "D": "勢いがなくなる。"}},
241: {"nativeDefinition": "To change one's opinion or attitude.", "japaneseMeaning": "考えを変える、口をひるがえす", "etymology": "change one's tune（調子を変える）が意見の転換を表す。", "examples": {"B": "牛乳嫌いだったでしょ？これ試して。考え変わるよ。", "C": "なんで子どもが嫌いなの？自分の子どもができたら考え変わるよ。", "D": "意見を変える。"}},
242: {"nativeDefinition": "To be important or influential.", "japaneseMeaning": "（発言などが）重みがある、影響力がある", "etymology": "carry weight（重みを持つ）が重要性を表す。", "examples": {"B": "履歴書に推薦状を添付して。評価プロセスで重みがある。", "C": "インフルエンサーとしてあのコメントすべきじゃなかった。自分の言葉が重みがあることをもっと意識すべきだった。", "D": "重要または影響力がある。"}},
243: {"nativeDefinition": "I am certain that something is true.", "japaneseMeaning": "〜だと確信している", "etymology": "I'm convinced（説得された＝確信している）が強い確信を表す。", "examples": {"B": "新しいコーチを雇うと最初からやり直しになる。カルロの下で順調に進んでるのに、判断するには早すぎる。", "C": "スティーブ・ジョブズが生きてたら、もっと革新的なiPhoneを作ってたと確信してる。", "D": "確信している。"}},
244: {"nativeDefinition": "Greatest Of All Time; the best ever.", "japaneseMeaning": "史上最高（GOAT）", "etymology": "GOATはGreatest Of All Timeの頭字語。", "examples": {"B": "間違いなくロナウドは偉大な選手だけど、本当のGOATはペレだ。", "C": "ロバート・デ・ニーロがGOAT。いい映画がたくさんあるし、いい人でもある。", "D": "史上最高。"}},
245: {"nativeDefinition": "In an unstable or uncertain situation.", "japaneseMeaning": "不安定な立場の、危うい", "etymology": "on shaky ground（揺れる地面の上）が不安定な状況を表す。", "examples": {"B": "YouTubeやInstagramなど外部プラットフォームに依存するビジネスは不安定な立場にいる。", "C": "別れたのは驚かない。15年付き合って結婚しなかったのは、関係が危ういサインだったと思う。", "D": "不安定な。"}},
246: {"nativeDefinition": "With sincere and genuine feeling.", "japaneseMeaning": "心からの、本心から", "etymology": "from the heart（心から）が誠実な感情を表す。", "examples": {"B": "心からの感動的なスピーチだった。録画しなかったことを今すごく後悔してる。", "C": "心からの贈り物、ありがとう。一日が明るくなった。", "D": "誠実な感情で。"}},
247: {"nativeDefinition": "To understand the mood or atmosphere of a situation.", "japaneseMeaning": "空気を読む", "etymology": "read the room（部屋を読む）が場の雰囲気を察することを表す。", "examples": {"B": "おい、空気読めよ。みんな残業して出荷に追われてる。来週スペイン旅行がどれだけ楽しみかなんて誰も聞きたくない。", "C": "ジャックは面白い人だけど、たまに空気読んでほしい。", "D": "雰囲気を理解する。"}},
248: {"nativeDefinition": "A corny or predictable joke, typically told by fathers.", "japaneseMeaning": "おやじギャグ、ダジャレ", "etymology": "dad joke（お父さんのジョーク）が古いダジャレを表す。", "examples": {"B": "ある見方をすると、ピートのおやじギャグは実は結構面白い。全員にはウケないけど。", "C": "父がおやじギャグを始めるたびに、母が遮る。", "D": "お父さんだけが笑うジョーク。"}},
249: {"nativeDefinition": "I don't believe it! (expressing surprise or disbelief)", "japaneseMeaning": "まさか！、嘘でしょ", "etymology": "get out of here（ここから出て行け）が驚きの反応として使われる。", "examples": {"B": "まさか！一日で100万ドル稼いだの？", "C": "まさか！アメリカ大統領が直接連絡してきたの？", "D": "信じられない。"}},
250: {"nativeDefinition": "To say something unintentionally.", "japaneseMeaning": "（言葉が）つい口から出る、うっかり言ってしまう", "etymology": "slip out（滑り出る）が意図せず言ってしまうことを表す。", "examples": {"B": "くしゃみのときチワワみたいに聞こえるなんて言うつもりなかった。つい口から出た。", "C": "彼女に愛してるって言っちゃってごめん。ちょっと飲んでて、うっかり出た。", "D": "不注意に言われる。"}},
251: {"nativeDefinition": "At the same level or standard as something else.", "japaneseMeaning": "（〜と）同等の、肩を並べる", "etymology": "on par with（〜と同じ水準で）が同等を表す。", "examples": {"B": "最近この新しい検索エンジン使ってる。結果はだいたいGoogleと同等だけど、Googleアカウントとかがない分、快適。", "C": "ここ数年ボイストレーニングしてるけど、まだプロ歌手には及ばない。", "D": "何かと同じレベルで。"}},
252: {"nativeDefinition": "To push through something with determination.", "japaneseMeaning": "（困難を）力ずくで乗り切る", "etymology": "power through（力で通す）が根性で乗り切ることを表す。", "examples": {"B": "あの昼寝は本当に命の恩人だった。寝ずに一日を力ずくで乗り切れた。", "C": "やる気があるうちに力ずくで終わらせないと。鉄は熱いうちに打て、って学んだから。", "D": "力強く何かを通過する。"}},
253: {"nativeDefinition": "To arrange something for someone, often as a favor.", "japaneseMeaning": "（人に〜を）手配する、つなぐ", "etymology": "hook up（つなぐ）が紹介や手配を表すスラング。", "examples": {"B": "高給の仕事手配してくれる人いない？経験はないけど、学ぶ意欲はある。", "C": "コネ使えばフロントのチケット手配できるけど、かなり高いよ。いい？", "D": "誰かに何かを手配する。"}},
254: {"nativeDefinition": "To reach the highest point of one's ability or popularity.", "japaneseMeaning": "（頂点に）達する、ピークを迎える", "etymology": "peak（頂点）が最高潮に達することを表す。", "examples": {"B": "彼女はずっと前にピークを迎えた。新しい曲を何年も聞いてない。", "C": "プロサッカー選手は25〜27歳でピークを迎えるってこのレポートに書いてある。若いね。", "D": "可能な限り最高レベルに達する。"}},
255: {"nativeDefinition": "To inform on someone; a person who informs.", "japaneseMeaning": "密告する、スパイ", "etymology": "snitch（密告者）が内密を漏らすことを表す。", "examples": {"B": "友達が宿題をコピーしたって密告した。裏切られた気分。", "C": "マークが密告者だと思う？会議中にネットショッピングしてたって上司に言ったの、誰か知ってる。君じゃないよね。", "D": "密告者。"}},
256: {"nativeDefinition": "From a different perspective or viewpoint.", "japaneseMeaning": "違う視点から、別のレンズで", "etymology": "through a different lens（違うレンズを通して）が視点の転換を表す。", "examples": {"B": "違う言語を学ぶだけで賢くなるかはわからないけど、違う視点で世界を見るのに役立つ。", "C": "問題を違う視点で見たら、核心にたどり着けた。", "D": "違う視点から。"}},
257: {"nativeDefinition": "A temporary lapse in memory or thinking.", "japaneseMeaning": "頭が真っ白、ブレインファート", "etymology": "brain fart（脳のおなら）が一時的な思考停止のスラング。", "examples": {"B": "やばい、頭が真っ白。あの有名なディズニーのネズミの名前なんだっけ？", "C": "ステージでブレインファートして面目丸潰れしたくないから、原稿から読むことにした。", "D": "一時的な思考の混乱。"}},
258: {"nativeDefinition": "To have a very kind and generous nature.", "japaneseMeaning": "心の底が優しい、金の心を持つ", "etymology": "heart of gold（金の心）が非常に優しい本性を表す。", "examples": {"B": "ステイシーはいつも彼氏を持ち上げてるけど、心の底が優しいのを見たことない。", "C": "ライアンは本当に心の底が優しい？本当だね。いつも他人のことを考えてる。", "D": "寛大で優しい性質を持つ。"}},
259: {"nativeDefinition": "To claim something for oneself before others.", "japaneseMeaning": "（〜を）取り置きする、先に取る", "etymology": "call dibs（取り置きを宣言する）が先取り権を主張するスラング。", "examples": {"B": "最後のピザの切れは僕が取った。午後のトレーニングにエネルギーが必要だから。", "C": "うちの犬はいつも助手席を取り置きするから、僕はいつも後部座席。", "D": "何かの権利を主張する。"}},
260: {"nativeDefinition": "To doubt or question a decision or judgment.", "japaneseMeaning": "（決断を）疑う、やり直す", "etymology": "second-guess（二度推測する）が判断を疑うことを表す。", "examples": {"B": "いつも自分の決断を疑っちゃう。もっと自信がほしい。", "C": "fortyのスペルはいつも疑う。fourみたいにuがないから。", "D": "何かを疑う。"}},
261: {"nativeDefinition": "In someone's opinion or judgment.", "japaneseMeaning": "（人にとって）〜だ、〜の目には", "etymology": "in one's eyes（人の目に）が主観的評価を表す。", "examples": {"B": "マイケル・ジョーダンは僕の目には史上最高の選手。", "C": "彼女は僕の目にはいつも完璧。", "D": "誰かの意見において。"}},
262: {"nativeDefinition": "An additional benefit that makes something even better.", "japaneseMeaning": "さらに良いもの、おまけ", "etymology": "icing on the cake（ケーキの上のアイシング）が上乗せの良さを表す。", "examples": {"B": "カフェのコーヒーは最高で、リラックスできる雰囲気がさらに良かった。", "C": "修士号がそのポジションに入る足がかりになると思う？それともおまけ程度？", "D": "状況をさらに良くするもの。"}},
263: {"nativeDefinition": "To make a great effort to help or please someone.", "japaneseMeaning": "（人のために）全力で尽くす", "etymology": "bend over backwards（後ろに反る）が過剰な努力を表す。", "examples": {"B": "おい、彼女に完全に従ってるじゃん。彼女が言うことにはいつも全力で応える。そうでしょ？", "C": "全力で助けたのに感謝もされないの、嫌だよね？", "D": "あらゆる努力をする。"}},
264: {"nativeDefinition": "Do what you want; it's your choice.", "japaneseMeaning": "好きにすればいい、あなたの自由", "etymology": "you do you（あなたはあなたをする）が他人の選択を尊重するスラング。", "examples": {"B": "この高級フレンチレストランでラップトップ使うの？変な目で見られるよ。でも好きにすればいいよ。", "C": "もっとチーズかけるの？十分だと思うけど、好きにして。", "D": "好きなことをする。"}},
265: {"nativeDefinition": "To watch carefully for something.", "japaneseMeaning": "（〜を）見張る、探す", "etymology": "keep one's eyes peeled（目を剥く）が注意深く見ることを表す。", "examples": {"B": "新しいエピソードが出るから、見張っておかないと。", "C": "仕事探してるんだね。見つけたら教えるよ。", "D": "気をつけて！"}},
266: {"nativeDefinition": "To refresh oneself, especially after physical activity.", "japaneseMeaning": "身だしなみを整える、さっぱりする", "etymology": "freshen up（新鮮にする）が身だしなみを整えることを表す。", "examples": {"B": "ディナーに行く前に、身だしなみ整える時間ちょうだい。", "C": "ワークアウト終わった。さっぱりしてから連絡するね。", "D": "自分をきれいにする。"}},
267: {"nativeDefinition": "Almost remembered but not quite.", "japaneseMeaning": "喉まで出かかっている、思い出せそうで思い出せない", "etymology": "on the tip of one's tongue（舌の先）が記憶の寸前を表す。", "examples": {"B": "ルーシーの名字が喉まで出かかってる。確かAで始まるんだけど、残りが思い出せない。", "C": "あ、この人知ってる。名前なんだっけ？喉まで出かかってるのに思い出せない。", "D": "もう少しで思い出せそう。"}},
268: {"nativeDefinition": "To notice oneself doing something unconsciously.", "japaneseMeaning": "（自分が〜してるのに）気づく", "etymology": "catch oneself（自分を捕まえる）が無意識の行動に気づくことを表す。", "examples": {"B": "運転中によくボーッとしてる自分に気づく。どうやって生きてるのかわからない。もっと気をつけないと。", "C": "緊張やストレスのとき、口の中側を噛んでる自分に気づくことがある。なんでだろう。", "D": "自分がしていることに気づく。"}},
269: {"nativeDefinition": "To lower oneself to someone's bad behavior level.", "japaneseMeaning": "（相手と）同レベルに堕ちる、相手に合わせる", "etymology": "sink to one's level（相手のレベルに沈む）が品位を落とすことを表す。", "examples": {"B": "お前と同レベルに堕ちてネットで喧嘩なんてしない。お前誰だよ？ごめん、忙しいんだ。", "C": "復讐に時間を無駄にしない。相手のレベルに堕ちたくない。", "D": "誰かと同じ低い行動をする。"}},
270: {"nativeDefinition": "To impress or amaze someone greatly.", "japaneseMeaning": "（人を）驚かせる、圧倒する", "etymology": "blow away（吹き飛ばす）が強い感動を与えることを表す。", "examples": {"B": "この超リアルな絵に圧倒された。一見写真だと思ったけど、鉛筆画だった。", "C": "トイレ掃除から始めて会社の社長になった。この男には圧倒される。", "D": "誰かを驚かせる。"}},
271: {"nativeDefinition": "Avoiding language that might offend particular groups.", "japaneseMeaning": "政治的に正しい、配慮した言葉遣い", "etymology": "politically correct（政治的に正しい）が差別的でない表現を表す。", "examples": {"B": "最近は政治的に正しすぎる気がする。いつもお互いの言葉を監視してるみたい。", "C": "日本人をJapsって呼び続けてるけど、政治的に正しくないと思う。", "D": "攻撃的でない。"}},
272: {"nativeDefinition": "Consecutively without a break.", "japaneseMeaning": "（休みなく）続けて、連続で", "etymology": "straight（まっすぐ）が連続を表す。", "examples": {"B": "大きな発言だけど、2〜3週間何も食べずにいける自信ある。", "C": "20日連続で働いてる。週末は髪を下ろしたい。", "D": "連続して。"}},
273: {"nativeDefinition": "Fortunately; it's lucky that something happened.", "japaneseMeaning": "〜があってよかった、幸い", "etymology": "good thing（良いこと）が幸運な結果を表す。", "examples": {"B": "昨夜すごく疲れてアラームをセットし忘れた。早起きできてよかった。", "C": "一緒にいてくれてよかった。あの怖い男に一人で立ち向かえなかったと思う。", "D": "幸い何かがそうする。"}},
274: {"nativeDefinition": "Simplicity is better; less is more effective.", "japaneseMeaning": "少ない方がいい、シンプルイズベスト", "etymology": "less is more（少ないことは多い）がミニマリズムの考え方を表す。", "examples": {"B": "校長はいつも長々と話す。要点を言えよ。少ない方がいいってわかってない。", "C": "少ない方がいいと信じてるから、アパートにはソファとテーブルしかない。", "D": "シンプルな方がいい。"}},
275: {"nativeDefinition": "Completely empty and deserted.", "japaneseMeaning": "ガラガラの、誰もいない", "etymology": "ghost town（ゴーストタウン）が人気のない状態を表す。", "examples": {"B": "今朝のコストコはガラガラだった。天気のせいかも。", "C": "クリスマス後に観光客が帰ると、このレストランはガラガラになる。", "D": "誰もいない。"}},
276: {"nativeDefinition": "To make someone feel uncomfortable or disturbed.", "japaneseMeaning": "（人を）気持ち悪がらせる、違和感を与える", "etymology": "weird out（変にする）が不快感を与えるスラング。", "examples": {"B": "コニーが昨夜キッチンで突然踊り始めたの、なんで？君も気持ち悪かった？", "C": "青信号が僕を気持ち悪がらせる。いつも黄色だと思ってる。", "D": "誰かを不快にさせる。"}},
277: {"nativeDefinition": "To end a relationship with someone.", "japaneseMeaning": "（人と）縁を切る、関係を断つ", "etymology": "cut ties（絆を切る）が関係を終わらせることを表す。", "examples": {"B": "ピートが突然縁を切った理由がわからない。コーヒーをかけたから？好きなスカーフ？", "C": "ジョシュとは縁を切った。彼女の誕生日サプライズをバラしたから。2ヶ月以上準備してたのに。", "D": "誰かとの関係を終わらせる。"}},
278: {"nativeDefinition": "To dislike someone and treat them unfairly.", "japaneseMeaning": "（人に）意地悪する、恨みを持っている", "etymology": "have it in for（〜に対してある）が根に持っていることを表す。", "examples": {"B": "また？なんでポールが意地悪してると思う？先週話したら、君たちは親友みたいに話してたよ。", "C": "誰かに悪口言われるだけで意地悪してるとは限らない。", "D": "嫌ったり恨みを持ったりする。"}},
279: {"nativeDefinition": "A person who is both a friend and an enemy.", "japaneseMeaning": "フレネミー、友達みたいな敵", "etymology": "friend（友達）＋enemy（敵）の造語。", "examples": {"B": "アイスクリームはフレネミー。美味しいけど太る。", "C": "大学の友達のパーティーに行くことになってるけど、あまり行きたくない。どっちかというとフレネミーだし。何て言えばいい？", "D": "友達のふりをする敵。"}},
280: {"nativeDefinition": "Forgetful or not paying attention.", "japaneseMeaning": "上の空の、ぼんやりした", "etymology": "absent-minded（不在の心）が注意力が散漫なことを表す。", "examples": {"B": "最近かなり上の空だ。年のせいかな。", "C": "すごく上の空。スマホを20分探してたら、目の前にあった。", "D": "不注意な。"}},
281: {"nativeDefinition": "An imagination that creates exaggerated or unrealistic thoughts.", "japaneseMeaning": "想像力が豊かすぎる、妄想癖", "etymology": "overactive（過剰に活動的な）imagination（想像力）が空想癖を表す。", "examples": {"B": "想像力が豊かすぎて、暗闇が怖いときがある。影に何か隠れてると思っちゃう。", "C": "あの雲、ドラゴンに見えない？僕の想像力が豊かすぎるだけか。", "D": "物事を誇張する想像力。"}},
282: {"nativeDefinition": "To publicly reject or boycott someone for controversial behavior.", "japaneseMeaning": "（人を）キャンセルする、追放する", "etymology": "cancel（キャンセル）がSNS時代の追放を表すスラング。", "examples": {"B": "このコメディアンはキャンセルされて魂の浄化の巡礼に出てる。あまり効果なさそう。", "C": "ひどい性差別コメントが最後の一押しだった。彼はキャンセルだ。", "D": "誰かをボイコットする。"}},
283: {"nativeDefinition": "A dominant, confident, and assertive person.", "japaneseMeaning": "アルファ（支配的な人）", "etymology": "alpha（アルファ）が群れのリーダーから転じたスラング。", "examples": {"B": "みんなにアルファ男だって言っても、そうとは限らない。行動が物を言う。", "C": "ジョシュは賢くて自信があって勇敢で、女性に慕われてる。間違いなくアルファだ。", "D": "支配的な人。"}},
284: {"nativeDefinition": "To advance through promotions in a company.", "japaneseMeaning": "出世する、キャリアアップする", "etymology": "corporate ladder（企業のはしご）が昇進の階段を表す。", "examples": {"B": "出世に夢中だったけど、最初の息子が生まれて仕事以外にも人生があると気づいた。", "C": "父はキャリアの選択肢は2つだと言った。出世するか、自分のビジネスを作るか。数週間悩んで仕事を辞めた。", "D": "昇進を通じて会社で進歩する。"}},
285: {"nativeDefinition": "The most effective or recommended way to do something.", "japaneseMeaning": "ベストプラクティス、最善の方法", "etymology": "best practice（最良の実践）が推奨される方法を表す。", "examples": {"B": "米を炊く前に洗うのがベストプラクティスだけど、面倒でやらない。", "C": "ミニマリストになるベストプラクティスを学びたいなら、この動画を見て。", "D": "理想的なプロセス。"}},
286: {"nativeDefinition": "To do something mechanically without real effort or interest.", "japaneseMeaning": "形だけこなす、なんとなくやる", "etymology": "go through the motions（動きを通す）が形式的にやることを表す。", "examples": {"B": "来週辞めるから、今は形だけこなしてる。上司が喜ぶかどうかもう気にしない。", "C": "成功する選手は練習で形だけこなすことは絶対しない。", "D": "あまり努力せずに何かをする。"}},
287: {"nativeDefinition": "An attractive older man with gray or white hair.", "japaneseMeaning": "シルバーフォックス、イケオジ", "etymology": "silver（銀色）＋fox（キツネ）が白髪の魅力的な男性を表す。", "examples": {"B": "今の人生目標は、セクシーで物知りなシルバーフォックスになること。", "C": "この写真の父は本物のシルバーフォックスに見えるって思うでしょ？実際に会ったらがっかりするよ。", "D": "ハンサムな年配の男性。"}},
288: {"nativeDefinition": "Not while someone is responsible for preventing it.", "japaneseMeaning": "（自分が）見ている限りは許さない", "etymology": "not on one's watch（自分の見張り中ではない）が責任を果たすことを表す。", "examples": {"B": "母がお気に入りのぬいぐるみを捨てそうになった。僕が見てる限りは許さない。", "C": "僕が責任者の間、性差別的なコメントは許さない。", "D": "誰かが責任者の間は。"}},
289: {"nativeDefinition": "To be unaware of the wider world or reality outside one's experience.", "japaneseMeaning": "世間知らずの、閉じた世界にいる", "etymology": "live in a bubble（泡の中に住む）が閉じた世界にいることを表す。", "examples": {"B": "自分の街にホームレスがいないと思ってるなんて信じられない。本当に世間知らずだ。", "C": "去年世界を旅して、ずっと閉じた世界に生きてたと気づいた。いい目覚めだった。", "D": "自分の世界しか意識していない。"}},
290: {"nativeDefinition": "A situation where it is difficult to meet high expectations set by a predecessor.", "japaneseMeaning": "大きな靴を履く、高い期待に応える", "etymology": "big shoes to fill（埋める大きな靴）が前任者の大きな足跡を表す。", "examples": {"B": "父が退職して会社を引き継いだ。大きな靴を履くことだけど、今のところなんとかやってる。", "C": "お疲れ様、次の仕事で頑張って。会社に大きく貢献してくれた。次の人は大きな靴を履くことになるね。", "D": "応えるべき高い期待。"}},
291: {"nativeDefinition": "To start fresh; to reset one's life or situation.", "japaneseMeaning": "リセットする、やり直す", "etymology": "hit the reset button（リセットボタンを押す）が再スタートを表す。", "examples": {"B": "ロックダウンはつらいけど、人生の多くの部分をリセットする機会をくれた。", "C": "かなり働きすぎてるから、休暇に行ってリセットする。", "D": "やり直す。"}},
292: {"nativeDefinition": "Nothing is better than this; it's the best.", "japaneseMeaning": "これに勝るものはない", "etymology": "there's nothing like（〜のようなものはない）が最高であることを表す。", "examples": {"B": "バック・トゥ・ザ・フューチャーは最高。これに勝るものはない。10代のとき見て度肝を抜かれた。SF映画のゴールドスタンダード。", "C": "海の音で目覚めて、新鮮なコーヒーの香り。これに勝るものはない。", "D": "何かが最高である。"}},
293: {"nativeDefinition": "Something that makes you cry; very emotional.", "japaneseMeaning": "泣ける、感動的な", "etymology": "tear-jerker（涙を引き出すもの）が感動で泣かせる作品を表す。", "examples": {"B": "この映画はすごく泣ける。なぜかはっきりわからない。音楽かも。", "C": "この本は本当に泣ける。読むたびに感情が込み上げてくる。", "D": "泣きたくなるもの。"}},
294: {"nativeDefinition": "To understate something; putting it mildly.", "japaneseMeaning": "控えめに言っても、遠慮なく言えば", "etymology": "to put it mildly（穏やかに言えば）が控えめな表現を表す。", "examples": {"B": "控えめに言っても、これまでのパフォーマンスはがっかりだ。", "C": "遠慮なく言えば、昨夜のコンサートは最高だった。", "D": "控えめに言って。"}},
295: {"nativeDefinition": "To admire someone excessively; to idealize them.", "japaneseMeaning": "（人を）神格化する、理想化する", "etymology": "put on a pedestal（台座に乗せる）が過度に持ち上げることを表す。", "examples": {"B": "僕を神格化しないで。ただ考えを共有してるだけで、間違ってるかもしれない。", "C": "金持ちで有名だからって神格化して、過去のひどい行いを見逃すべきじゃない。", "D": "誰かを崇拝する。"}},
296: {"nativeDefinition": "Not suited or qualified for a particular role or task.", "japaneseMeaning": "（〜の）適性がない、向いてない", "etymology": "not cut out to（切り出されていない）が天性の適性がないことを表す。", "examples": {"B": "外科医になる適性はないと思う。血を見るたびにパニックになる。", "C": "彼はパイロットに向いてない。高所恐怖症だから。", "D": "〜するために作られていない。"}},
297: {"nativeDefinition": "A person who prefers to act alone rather than with others.", "japaneseMeaning": "一匹狼、単独行動派", "etymology": "lone wolf（一匹狼）が群れを好まない人を表す。", "examples": {"B": "一匹狼だからって人が嫌いなわけじゃない。一人の時間が好きなだけ。", "C": "彼女は本当に一匹狼。誰かとランチしてるところ見たことない。", "D": "一人でいることを好む人。"}},
298: {"nativeDefinition": "Nothing valuable comes without cost or effort.", "japaneseMeaning": "タダより高いものはない", "etymology": "no free lunch（無料のランチはない）が無償の利益はないという格言。", "examples": {"B": "無料でiPhoneもらえる、条件なし？絶対詐欺だ。タダより高いものはない。", "C": "成功は運任せじゃなく、努力の結果。タダより高いものはない。", "D": "価値のあるものは無料ではない。"}},
299: {"nativeDefinition": "Suffering or hard work is necessary to achieve something.", "japaneseMeaning": "痛みなくして得るものなし", "etymology": "no pain, no gain（痛みなくして得なし）が努力の必要性を表すスポーツ格言。", "examples": {"B": "結婚式のスーツに入るために3週間チキンとブロッコリーだけ食べる。痛みなくして得るものなしかな。", "C": "週末のハイキングは膝をボロボロにするけど、頂上の景色は最高だった。痛みなくして得るものなし、だよね？", "D": "何かを達成するには苦しみが必要。"}},
300: {"nativeDefinition": "An acceptable cost or sacrifice for a greater benefit.", "japaneseMeaning": "安いもんだ、小さな代償", "etymology": "a small price to pay（払う小さな代償）が許容できる犠牲を表す。", "examples": {"B": "日本のタクシー料金は高いけど、この美しい国に住むための小さな代償だ。", "C": "ダウンジャケットがちょっとバカみたいに見えるのはわかってるけど、暖かさのための小さな代償だ。", "D": "許容できるコスト。"}},
}
